import { createApp, h, ref, onMounted, nextTick } from 'vue';
import SocketService from './SocketService.js';

export function showReconnectDialog(onConfirm) {
  const visible = ref(true);

  // ============== 从 URL ?lang=en 获取语言 ==============
  const getCurrentLang = () => {
    const urlParams = new URLSearchParams(window.location.search);
    const lang = urlParams.get('lang');
    // 支持 zh / en，默认中文
    return ['zh', 'en', 'ru', 'pt', 'vn'].includes(lang) ? lang : 'en';
  };

const i18n = {
  // 中文
  zh: {
    title: '提示',
    message: '网络已断开，是否重新连接？',
    cancel: '取消',
    confirm: '确定',
  },
  // 英文
  en: {
    title: 'Notice',
    message: 'Connection lost, reconnect?',
    cancel: 'Cancel',
    confirm: 'Confirm',
  },
  // 俄语
  ru: {
    title: 'Уведомление',
    message: 'Соединение потеряно, переподключиться?',
    cancel: 'Отмена',
    confirm: 'ОК',
  },
  // 葡萄牙语
  pt: {
    title: 'Aviso',
    message: 'Conexão perdida, reconectar?',
    cancel: 'Cancelar',
    confirm: 'Confirmar',
  },
  // 越南语
  vn: {
    title: 'Thông báo',
    message: 'Mất kết nối mạng, kết nối lại?',
    cancel: 'Hủy',
    confirm: 'Đồng ý',
  },
};

  const currentLang = getCurrentLang();
  const t = i18n[currentLang];
  // ======================================================

  const DialogComponent = {
    setup() {
      const handleCancel = () => {
        visible.value = false;
        app.unmount();
        container.remove();

        if (document.referrer && document.referrer.length > 0) {
          window.history.back();
          return;
        }
        location.reload();
      };

      const handleConfirm = () => {
        visible.value = false;
        app.unmount();
        container.remove();

       
          SocketService.Instance.continueRetry();
        
      };

      const adjustFont = (el, maxFont = 20, minFont = 12) => {
        if (!el) return;
        let fontSize = maxFont;
        el.style.fontSize = fontSize + 'px';
        while (el.scrollWidth > el.clientWidth && fontSize > minFont) {
          fontSize -= 1;
          el.style.fontSize = fontSize + 'px';
        }
      };

      onMounted(() => {
        nextTick(() => {
          const cancelBtn = document.getElementById('cancel-btn');
          const confirmBtn = document.getElementById('confirm-btn');
          adjustFont(cancelBtn);
          adjustFont(confirmBtn);
        });
      });

      return () =>
        visible.value
          ? h(
              'div',
              {
                style: `
                  position: fixed;
                  top:0; left:0;
                  width:100vw; height:100vh;
                  background: rgba(0,0,0,0.5);
                  display:flex;
                  justify-content:center;
                  align-items:center;
                  z-index:9999;
                `
              },
              [
                h(
                  'div',
                  {
                    style: `
                      background: rgba(0,0,0,0.85);
                      padding: 30px 40px;
                      border-radius: 12px;
                      width:400px;
                      max-width:90vw;
                      text-align:center;
                      box-shadow: 0 10px 25px rgba(0,0,0,0.5);
                      color: #f0f0f0;
                      font-family: 'Segoe UI', sans-serif;
                    `
                  },
                  [
                    h('h3', { style: 'margin-bottom:15px; font-size:26px;' }, t.title),
                    h('p', { style: 'margin-bottom:30px;font-size:18px;line-height:1.6;' }, t.message),
                    h('div', { style: 'display:flex; justify-content:space-between; gap:10px;' }, [
                      h(
                        'button',
                        {
                          id: 'cancel-btn',
                          style: `flex:1;height:50px;border:none;border-radius:6px;background:#28a745;color:#fff;font-weight:bold;cursor:pointer;`,
                          onClick: handleCancel
                        },
                        t.cancel
                      ),
                      h(
                        'button',
                        {
                          id: 'confirm-btn',
                          style: `flex:1;height:50px;border:none;border-radius:6px;background:#dc3545;color:#fff;font-weight:bold;cursor:pointer;`,
                          onClick: handleConfirm
                        },
                        t.confirm
                      ),
                    ])
                  ]
                )
              ]
            )
          : null;
    }
  };

  const container = document.createElement('div');
  document.body.appendChild(container);
  const app = createApp(DialogComponent);
  app.mount(container);
}